// PCA Ordination & Licensure Study — per-card MCQ overlay: theology.
// Hand-authored multiple-choice for cards that can't auto-generate one, keyed
// by card id and merged into window.PCA_CARD_QUIZ (consumed by
// js/app/quiz.js cardQuiz()). Kept OUTSIDE the generated subject files so a
// builder re-run never wipes these. Each entry:
//   'card-id': { q?: 'sharper question override', choices: [4], answerIndex }
// Distractors must match the correct answer in length and grammatical shape
// (dev/validate.mjs giveaway check + manual discipline).
(function (global) {
  const Q = {
    // ── A. The Bible ──────────────────────────────────────────────────
    'th-001-define-and-distinguish-general-rev': { q: 'Which best distinguishes general revelation from special revelation?', choices: ['General revelation is God’s self-disclosure to all people through creation and conscience, while special revelation is his particular communication to specific persons through Scripture.', 'General revelation is God’s saving self-disclosure given only through Scripture, while special revelation is his disclosure to all people through creation and conscience.', 'General revelation is the Spirit’s inward witness given to individual believers, while special revelation is the church’s official teaching passed down through tradition.', 'General revelation is the covenant of grace revealed uniquely to national Israel, while special revelation is the light of nature given equally to every nation.'], answerIndex: 0 },
    'th-002-define-and-defend-including-script': { q: 'What best defines the doctrine of “inspiration,” per WCF I.2 and WLC 4?', choices: ['The supernatural illumination given to modern readers, so that any sincere interpretation becomes God’s own word.', 'The supernatural work of the Holy Spirit on the biblical writers, so that what they wrote is accurately God’s own word.', 'The church’s official decision to grant certain writings the same authority as God’s own word.', 'The general religious influence common to great writings, so that readers feel a sense of God’s own word.'], answerIndex: 1 },
    'th-003-define-and-defend-the-necessity-of': { q: 'What does the “necessity” of Scripture mean?', choices: ['Scripture is necessary for knowing that God exists, since nature and conscience reveal nothing of him at all.', 'Scripture is helpful for knowing the gospel but not strictly necessary, since sincere seekers may be saved apart from it.', 'Scripture is necessary for knowing the gospel and God’s will for salvation, though not for knowing that God exists at all.', 'Scripture is necessary only for ordained officers, since ordinary believers may rely on tradition and the Spirit’s leading.'], answerIndex: 2 },
    'th-004-what-is-the-canon-defend-it-script': { q: 'What is the “canon” of Scripture?', choices: ['The list of books the church created by conciliar decree, later invested, without dispute, with the authority of an apostolic origin.', 'The list of every ancient religious writing that mentions Israel’s God, regardless of its theological consistency.', 'The list of books whose authorship remains permanently debated, held provisionally pending further manuscript finds.', 'The list of books recognized by the church as belonging in the Bible, on the basis of apostolic authority, not decree.'], answerIndex: 3 },
    'th-005-define-and-defend-the-authority-of': { q: 'On what does the authority of Scripture rest, per WCF I.4?', choices: ['God himself, its divine author, rather than the testimony of any man or church.', 'The testimony and ratification of church councils, freely given, that formally approved each book.', 'The personal conviction each reader feels when Scripture resonates with experience.', 'The antiquity and literary excellence of its authors compared to other ancient texts.'], answerIndex: 0 },
    'th-006-define-and-defend-the-sufficiency': { q: 'What does the “sufficiency” of Scripture mean, per WCF I.6?', choices: ['Scripture contains most things necessary for salvation, faith, and life, but the church’s traditions must supply what still remains.', 'Scripture contains everything necessary for salvation, faith, and life, so nothing may be added by new revelations.', 'Scripture is sufficient for private devotion, but official doctrine still requires ongoing new revelations.', 'Scripture is sufficient for ethical guidance only, while private gnosis passed among elders reveals salvation itself.'], answerIndex: 1 },
    'th-007-define-and-defend-the-perspicuity': { q: 'What does the “perspicuity” (clarity) of Scripture mean?', choices: ['Every verse of Scripture is equally clear, without exception, so no passage ever requires careful study or comparison.', 'Only trained clergy can rightly grasp Scripture’s saving message, since ordinary readers easily misread it.', 'The central saving message of Scripture is clear enough that ordinary people, using ordinary means, can grasp it.', 'Scripture’s meaning shifts with each generation’s culture, so no fixed saving message can be identified.'], answerIndex: 2 },
    'th-008-what-is-distinctive-about-reformed': { q: 'What is distinctive about Reformed interpretation of Scripture, per WLC 156?', choices: ['Only ordained priests may read Scripture at all, since the laity risk grave doctrinal error.', 'Each reader may interpret Scripture freely, with no reference to the church’s historic creeds.', 'The church’s magisterium alone possesses the authority to determine Scripture’s true meaning.', 'Every believer has the right and duty to read and interpret Scripture personally, without a priest’s mediation.'], answerIndex: 3 },
    'th-009-what-principles-should-guide-our-i': { q: 'Which principle should guide interpretation of Scripture, per WCF I.9?', choices: ['Scripture interprets Scripture — unclear passages are searched out and known by other, clearer passages.', 'Church tradition interprets Scripture — unclear passages are settled, finally, by councils rather than by other texts.', 'Personal experience interprets Scripture — unclear passages are resolved by each reader’s private feelings.', 'Historical criticism interprets Scripture — unclear passages are resolved by reconstructing the author’s psychology.'], answerIndex: 0 },
    'th-010-define-and-defend-including-script': { q: 'What does the “inerrancy” of Scripture mean?', choices: ['Scripture in its current translations is verbally identical to the original manuscripts in every detail.', 'Scripture in the original manuscripts does not affirm anything that is contrary to fact.', 'Scripture’s central spiritual message is true even though many of its historical claims are legendary.', 'Scripture is inerrant only in matters of faith and morals, and may err in history or science.'], answerIndex: 1 },
    'th-011-what-do-the-scriptures-principally': { q: 'Per WSC 3, what do the Scriptures principally teach?', choices: ['What man is to build concerning society, and what laws the state requires of man.', 'What man is to feel concerning himself, and what practice fulfillment requires of man.', 'What man is to believe concerning God, and what duty God requires of man.', 'What man is to know concerning history, and what customs each culture requires of man.'], answerIndex: 2 },
    // ── B. God & His World ───────────────────────────────────────────
    'th-012-what-is-god': { q: 'Per WSC 4, what is God?', choices: ['A Spirit, finite in power though infinite in his goodness, holiness, justice, and truth.', 'The highest being within the created order, surpassing all creatures in wisdom, power, and holiness.', 'An impersonal force pervading the universe, unchangeable in its power, presence, and justice.', 'A Spirit, infinite, eternal, and unchangeable, in his being, wisdom, power, holiness, justice, goodness, and truth.'], answerIndex: 3 },
    'th-013-briefly-explain-and-defend-includi': { q: 'Which statement best expresses the doctrine of the Trinity?', choices: ['God eternally exists as three persons, Father, Son, and Holy Spirit, and each person is fully God, yet there is one God.', 'God is one person who successively reveals himself in three modes, as Father, then Son, then Holy Spirit.', 'God the Father alone is fully God, while the Son and the Holy Spirit are exalted creatures subordinate to him.', 'Father, Son, and Holy Spirit are three separate gods who cooperate in perfect unity of purpose and will.'], answerIndex: 0 },
    'th-014-what-are-the-attributes-of-god-be': { q: 'How does theology distinguish God’s communicable and incommunicable attributes?', choices: ['Communicable attributes are qualities God once had but has since laid aside, while incommunicable attributes remain his forever.', 'Communicable attributes are qualities God shares with his creatures, such as knowledge and love, while incommunicable attributes, such as eternity and omnipresence, belong to God alone.', 'Communicable attributes describe God’s acts, such as creation and providence, done in time, while incommunicable attributes describe his inner, unchanging nature, apart from any of his acts.', 'Communicable attributes are revealed only in Scripture, while incommunicable attributes are known only through general revelation.'], answerIndex: 1 },
    'th-015-what-are-the-decrees-of-god': { q: 'Per WSC 7, what are the decrees of God?', choices: ['His ongoing responses to human choices, shaped moment by moment, by which he continually adjusts his plans to fit what creatures freely decide.', 'His general wishes for creation, which he hopes will come to pass but cannot guarantee against human resistance.', 'His eternal purpose, according to the counsel of his will, whereby, for his own glory, he foreordained whatsoever comes to pass.', 'His temporary plans for national Israel, later abandoned once the church replaced Israel as God’s people.'], answerIndex: 2 },
    'th-016-what-is-the-difference-between-inf': { q: 'What is the key difference between supralapsarianism and infralapsarianism?', choices: ['Supralapsarianism denies that God decreed the fall at all, while infralapsarianism affirms he decreed and directly caused it.', 'Supralapsarianism teaches a universal atonement for all, while infralapsarianism restricts the atonement’s intent to the elect.', 'Supralapsarianism holds predestination is conditioned on foreseen faith, while infralapsarianism holds it is wholly unconditional.', 'Supralapsarianism places the decree to elect before the decree to permit the fall, while infralapsarianism places it after.'], answerIndex: 3 },
    'th-017-what-is-an-amyraldian-view-of-god': { q: 'What distinguishes the Amyraldian view of God’s decrees from the Reformed consensus?', choices: ['Christ dies for all conditioned on belief, and the Spirit is then given effectually only to the elect — hypothetical universal predestination.', 'Christ dies only for the elect, and the Spirit is then offered indiscriminately to all who ask for it.', 'All people are predestined to salvation unconditionally, with no place for reprobation of any kind.', 'Election is based on God’s foreknowledge of each person’s inherent goodness and moral effort — a synergistic, works-conditioned view of predestination.'], answerIndex: 0 },
    'th-018-how-does-god-execute-his-decrees': { q: 'Per WSC 8, how does God execute his decrees?', choices: ['In the works of judgment and destruction alone.', 'In the works of creation and providence.', 'In the sacraments and the preaching of the Word alone.', 'In the covenant of works given only to Adam.'], answerIndex: 1 },
    'th-019-what-is-god-s-work-of-creation': { q: 'Per WSC 9, what is the work of creation?', choices: ['God’s making all things out of pre-existing matter, over long ages, gradually shaped into their present forms.', 'God’s making the spiritual realm alone, leaving the material world to arise through natural processes.', 'God’s making all things of nothing, by the word of his power, in the space of six days, and all very good.', 'God’s making all things of nothing in a single timeless moment, with no sequence of days at all.'], answerIndex: 2 },
    'th-020-briefly-discuss-the-length-of-the': { q: 'Which pairing of a creation-days theory with its view of “day” is correct?', choices: ['Day-age theory: a sequential, literal reading in which each creation day is a normal 24-hour period.', 'Literary framework theory: a chronological record in which each day marks a distinct geological epoch.', 'Two-phase theory: a single 24-hour day with no possible gap between Genesis 1 and 2.', '24-hour day theory: a sequential, literal reading in which each creation day is a normal 24-hour period.'], answerIndex: 3 },
    'th-021-evaluate-biblically-the-theory-of': { q: 'What is the biblical evaluation of macro-evolutionary theory, per the card?', choices: ['Micro-evolution is a fact, but extrapolating it into full macro-evolution is scientifically suspect and conflicts with Genesis 2-3 and Romans 5 on the origin of death.', 'Both micro- and macro-evolution are fully compatible with Genesis, since death entered creation long before Adam’s sin.', 'Macro-evolution is certain, well-established science that Christians must simply reinterpret Genesis 1-3 to accommodate, since the two accounts cannot otherwise be reconciled.', 'Neither micro- nor macro-evolution has any observable basis, so all genotypic change in species must be denied.'], answerIndex: 0 },
    'th-022-what-are-god-s-work-s-of-providenc': { q: 'Per WSC 11, what are God’s works of providence?', choices: ['His occasional interventions in a world otherwise left to run by chance and impersonal natural law.', 'His most holy, wise, and powerful preserving and governing of all his creatures and all their actions.', 'His governing of the church alone, wise though limited, leaving the wider natural world to operate independently of him.', 'His preserving only the elect, while abandoning the reprobate and the created order to themselves.'], answerIndex: 1 },
    'th-023-what-is-a-miracle': { q: 'How does WCF V.3 and Berkhof define a miracle?', choices: ['Any surprising or improbable event in nature, however it may ultimately be explained by ordinary secondary causes.', 'God’s ordinary providence, working exclusively through the normal means he has established in creation.', 'A supernatural work of God, done without recourse to the ordinary means by which he usually governs.', 'A psychological experience of wonder in the believer, regardless of whether anything unusual actually occurred.'], answerIndex: 2 },
    'th-024-do-miracles-occur-today-explain': { q: 'Do miracles occur today, per the card’s answer?', choices: ['No, miracles ceased entirely and permanently once the apostolic age and the canon of Scripture closed.', 'Yes, and miracle-working today should be expected as the ordinary experience of every believer.', 'No, every reported healing today can be fully explained by natural, ordinary secondary causes.', 'Yes, though rarely — God is free to work outside ordinary providence at his pleasure, though not as the apostolic norm.'], answerIndex: 3 },
    'th-025-is-god-responsible-for-sin': { q: 'Is God responsible for sin, per WCF III.1 and V.4?', choices: ['No — God ordains whatsoever comes to pass, yet he is not the author of sin; its sinfulness proceeds only from the creature.', 'Yes — since God ordains whatsoever comes to pass, he must also be the author and approver of sin itself.', 'No — God merely observes sin from a distance and has no decree relating to it whatsoever.', 'Yes — God is equally the author of good and evil, since both proceed from his single, undifferentiated will.'], answerIndex: 0 },
    'th-026-if-god-is-good-and-all-powerful-ex': { q: 'How does the card explain suffering such as AIDS, deformed babies, and natural disasters, given God’s goodness and power?', choices: ['Such suffering proves that God, though good, lacks the power to prevent evil in a fallen world.', 'The world is fallen because of Adam’s sin, so tragedy afflicts even the innocent, and Job teaches us to trust the giver above his gifts.', 'Such suffering falls only on the especially wicked, as direct, individual, and proportionate punishment for particular sins they alone committed.', 'Such suffering is an illusion, since a good and all-powerful God would never permit any real affliction.'], answerIndex: 1 },
    'th-027-discuss-the-biblical-teaching-rega': { q: 'Per WCF III.3-8, how does the Bible teach predestination, election, and reprobation?', choices: ['God predestines everyone equally to everlasting life, so reprobation is not a genuine biblical category at all.', 'God elects based on foreseeing, before the foundation of the world, which individuals would freely choose faith and freely persevere in it to the end.', 'God has predestinated some to everlasting life in Christ and foreordained others to everlasting death for their sin, to be handled with prudence.', 'God elects entire nations corporately, with no reference to the eternal destiny of individual persons.'], answerIndex: 2 },
    'th-028-distinguish-the-reformed-and-armin': { q: 'How does the card distinguish the Reformed and Arminian views of predestination?', choices: ['Reformed theology holds conditional election based on foreseen faith, while Arminians hold it is wholly unconditional.', 'Reformed theology and Arminian theology agree entirely on predestination, differing only on the nature of the church.', 'Reformed theology denies election altogether, while Arminians affirm unconditional election in eternity past.', 'Reformed theology holds unconditional election in Christ, while Arminians hold conditional predestination based on foreseen faith.'], answerIndex: 3 },
    'th-029-are-these-doctrines-compatible-wit': { q: 'Are God’s sovereign decrees compatible with real human choice and responsibility, per the card?', choices: ['Yes — Scripture is compatibilistic: Genesis 50:20 and Acts 2:23 show God standing sovereignly behind human choices for which people remain genuinely responsible.', 'No — if God ordains all things down to the smallest detail, human choices must be a complete illusion with no real moral responsibility attached to anyone.', 'Yes, but only because God’s decrees are actually conditioned on and reactive to human choices he foresees.', 'No — Scripture teaches that human responsibility applies only in matters God has not decreed in advance.'], answerIndex: 0 },
    'th-030-what-should-be-some-of-the-practic': { q: 'What practical results does WCF III.8 draw from the doctrine of election?', choices: ['Complacency about evangelism, carelessness about holiness, and neglect of the means of grace, since the elect are secure regardless of human effort.', 'Gratitude for unmerited adoption, assurance that salvation is secure in God, and evangelistic zeal since the Lord has other sheep to gather.', 'Anxious self-examination that never reaches assurance, since no one can know whether they are truly elect.', 'Pride in one’s own spiritual achievement, since being chosen shows one is inherently better than others.'], answerIndex: 1 },
    'th-031-is-there-a-real-personal-devil-exp': { q: 'Is there a real, personal devil, per the card’s answer from Scripture?', choices: ['No — the devil, like other supernatural symbols, is merely a literary personification of impersonal evil forces within the human heart.', 'Yes, but only as an equal and opposite power locked in eternal struggle with God.', 'Yes — the temptation accounts, such as Matthew 4:1-11, portray the devil as both real and personal.', 'No — Scripture never actually portrays the devil as a distinct personal being at all.'], answerIndex: 2 },
    // ── C. Humankind ─────────────────────────────────────────────────
    'th-032-what-is-the-chief-end-of-man': { q: 'Per WSC 1, what is the chief end of man?', choices: ['To pursue personal happiness, and to enjoy the created world, savoring its pleasures forever.', 'To obey the state, and to serve the common good of society forever.', 'To perfect the self, and to attain enlightenment through inner reflection.', 'To glorify God, and to enjoy him forever, doing all things to his glory.'], answerIndex: 3 },
    'th-033-what-is-the-supreme-activity-of-ma': { q: 'Per WSC 39, what does God require of man?', choices: ['Obedience to his revealed will, as made known to us in his Word.', 'Obedience to the traditions, however venerable, handed down by the church fathers.', 'Obedience to whatever conscience judges best in the moment.', 'Obedience to the civil laws enacted by each person’s nation.'], answerIndex: 0 },
    'th-034-what-does-the-bible-teach-about-th': { q: 'Per WSC 10, how did God create human beings?', choices: ['Male and female, after the image of the angels, in strength and beauty, with dominion over the angels themselves.', 'Male and female, after his own image, in knowledge, righteousness, and holiness, with dominion over the creatures.', 'As a single androgynous being later divided by God into a male half and a female half.', 'Male and female, evolved gradually from earlier animal forms, with no direct act of divine creation.'], answerIndex: 1 },
    'th-035-in-what-way-is-man-created-in-the': { q: 'In what way is man created in the image of God, per the card?', choices: ['Only structurally, through physical endowments like strength and physical beauty, with no functional dimension.', 'Only functionally, through ruling creation, with no structural endowments of rationality or morality involved.', 'Both functionally — ruling creation, loving God and neighbor — and structurally, through rationality, morality, and spirituality.', 'Only mystically, through an unknowable spark of divinity that grants no discernible capacities at all.'], answerIndex: 2 },
    'th-036-are-all-men-in-the-image-of-god-if': { q: 'Are all men in the image of God, and to what extent, per the card?', choices: ['Yes, but only believers retain the image of God, since unbelievers forfeited it entirely and permanently at the fall.', 'No, only Adam and Eve bore God’s image directly; their many descendants inherit no meaningful trace of it at all.', 'Yes, and the fall left the image of God completely untouched and fully unaffected in every man.', 'Yes, all are created in God’s image, though the fall has marred its functional exercise while its structural aspect remains.'], answerIndex: 3 },
    'th-037-how-does-the-doctrine-of-the-image': { q: 'How does the doctrine of the image of God inform the debate about gender roles, per the card?', choices: ['Men and women are equal in worth and dignity as image-bearers, yet Adam’s prior creation implies headship authority in the relationship.', 'Men and women are unequal in worth as image-bearers, since only the man fully bears God’s image.', 'Men and women are equal in worth and interchangeable in every role, since headship is nowhere implied by creation order.', 'Men and women are equal in worth, but the woman’s prior creation implies her headship authority in the relationship.'], answerIndex: 0 },
    'th-038-where-did-man-s-soul-come-from-whe': { q: 'Which of these correctly pairs a view of the soul’s origin with its definition?', choices: ['Creationism: the soul is propagated along with the body at generation, transmitted to children by their parents.', 'Traducianism: the soul is propagated along with the body at generation, transmitted to children by their parents.', 'Pre-existence: the soul is an immediate creation of God at a determinate moment after conception.', 'Traducianism: the soul existed in a previous state before being joined to the body at birth.'], answerIndex: 1 },
    'th-039-what-is-sin-see-wsc-14-include-scr': { q: 'Per WSC 14, what is sin?', choices: ['Any feeling of guilt, or shame, that a person experiences before God or others.', 'Any cultural custom that a particular society happens to regard as taboo.', 'Any want of conformity unto, or transgression of, the law of God.', 'Any failure to achieve one’s full personal potential in life.'], answerIndex: 2 },
    'th-040-discuss-the-guilt-of-sin-and-the-c': { q: 'How does WSC 18 distinguish the guilt and the corruption belonging to fallen man’s estate?', choices: ['Guilt is the corruption of nature inherited from Adam, while corruption is the actual sin each person personally commits.', 'Guilt belongs only to Adam himself, while corruption is inherited by all his descendants without any guilt at all.', 'Guilt and corruption are simply two names for the very same reality, with no distinction between them.', 'Guilt is inherited from Adam’s first sin, while corruption is the resulting want of original righteousness and depravity of nature.'], answerIndex: 3 },
    'th-041-define-and-discuss-original-sin-in': { q: 'Per WSC 16-18, what is original sin?', choices: ['Mankind, descending from Adam by ordinary generation, sinned in him and fell with him, inheriting guilt and corruption from his first transgression.', 'Each person’s own first personal sin, freely committed in youth, entirely independent of any connection to Adam’s original transgression or inherited guilt.', 'A merely symbolic label for humanity’s collective bad example, with no actual guilt or corruption inherited.', 'A corruption that affects only the body, leaving the soul and will entirely untouched by Adam’s fall.'], answerIndex: 0 },
    'th-042-how-can-original-sin-be-reconciled': { q: 'How can original sin be reconciled with the canons of justice, per the card?', choices: ['It cannot be reconciled; original sin is simply an unjust and arbitrary doctrine with no coherent defense.', 'Total depravity and inability do not relieve man of moral obligation, because his inability is self-imposed, grounded in Adam’s sin.', 'Man’s inability excuses him entirely of all moral obligation, since a person cannot be blamed, in fairness, for a nature he never personally chose.', 'God imposed the inability directly on each person at birth, apart from any connection to Adam’s sin.'], answerIndex: 1 },
    'th-043-is-there-any-good-remaining-in-a-f': { q: 'Is there any good remaining in a fallen, sinful man, per WCF VI.4 and IX.3?', choices: ['Fallen man retains full spiritual ability to please God and prepare himself for salvation by his own strength.', 'Fallen man has no good of any kind remaining, since the fall, in every sense, entirely erased the image of God from him and all his descendants.', 'Fallen man is utterly indisposed to spiritual good unto salvation, yet because he still bears God’s image, some natural good remains.', 'Fallen man’s corruption affects only his outward actions, leaving his inward will spiritually unaffected.'], answerIndex: 2 },
    'th-044-in-what-ways-does-man-sin': { q: 'In what ways does man sin, per the card’s definition (WSC 14)?', choices: ['Only by actively transgressing God’s law in thought, word, or deed, since falling short in mere want of conformity is not truly sin.', 'Only by wanting due conformity to God’s law, since active transgression is a separate category altogether.', 'Only by breaking civil statutes, since the moral law of God no longer defines sin under the new covenant.', 'Both by wanting the due conformity to God’s law that he requires and by actively transgressing that law in thought, word, or deed.'], answerIndex: 3 },
    'th-045-what-are-some-of-the-consequences': { q: 'Per WSC 18-19, what are the consequences of the fall into sin?', choices: ['Loss of communion with God, being under his wrath and curse, and liability to misery in this life, death, and hell forever.', 'A temporary estrangement from God’s fellowship that resolves automatically for everyone, believer and unbeliever alike, once natural life on earth ends.', 'Only physical death, with no liability to divine wrath, misery, or eternal punishment at all.', 'Merely a diminished self-esteem, without any objective change in one’s standing before God.'], answerIndex: 0 },
    'th-046-is-the-will-of-man-free-explain-in': { q: 'How does WCF IX describe the freedom of man’s will across each state?', choices: ['Adam’s will was already enslaved to sin before the very first transgression, just as every sinner’s and even every believer’s will still remains today.', 'Adam’s will was free to good or evil before the fall; the sinner’s will is enslaved to sin; the believer’s will is freed by grace, though imperfectly.', 'The sinner’s will retains full ability to turn to God unaided, exactly as Adam’s will did before the fall.', 'The believer’s will becomes perfectly free and sinless the moment of conversion, willing only what is good.'], answerIndex: 1 },
    // ── D. God's Way of Salvation ────────────────────────────────────
    'th-047-what-is-a-covenant': { q: 'What is a covenant, per the card?', choices: ['A unilateral gift given without any conditions, promises, or obligations placed on either party.', 'A private inner feeling of commitment, sincerely held, that requires no outward ceremony or stipulated terms at all.', 'A pact or agreement between two parties, confirmed by a solemn ceremony, binding each to promises on stipulated conditions.', 'A temporary truce between hostile parties that lapses automatically once tensions subside.'], answerIndex: 2 },
    'th-048-what-is-the-covenant-of-works-life': { q: 'Per WCF VII.2, what is the Covenant of Works (Life)?', choices: ['The first covenant made with man, wherein life was promised to Adam upon condition of imperfect, sincere obedience alone.', 'The covenant made with Noah, wherein natural blessings were promised upon condition of ritual sacrifice.', 'The covenant made with Abraham, wherein life was promised to his descendants upon condition of circumcision.', 'The first covenant made with man, wherein life was promised to Adam and his posterity upon condition of perfect obedience.'], answerIndex: 3 },
    'th-049-is-there-a-present-validity-to-the': { q: 'Is there a present validity to the Covenant of Works (Life), per the card?', choices: ['Yes and no — Christ has fulfilled its demands so that believers do not have to, receiving the fruits of his work through grace.', 'No, the Covenant of Works was entirely abrogated at the fall and has had no bearing on redemption ever since.', 'Yes, believers today must still perfectly keep the law themselves to earn eternal life, just as Adam did.', 'Yes and no — Christ merely modeled obedience for believers, who must then independently earn their own righteousness.'], answerIndex: 0 },
    'th-050-what-is-the-covenant-of-redemption': { q: 'What is the Covenant of Redemption, per the card?', choices: ['The eternal agreement between the Father, offering salvation to all humanity, conditioned only on each person’s own foreseen acceptance of the gospel.', 'The eternal agreement between the Father, giving the Son as Head and Redeemer of the elect, and the Son, voluntarily taking their place.', 'The temporal agreement made at Sinai between God and the nation of Israel through the mediation of Moses.', 'The eternal agreement between the Son and the church, in which believers voluntarily take Christ’s place.'], answerIndex: 1 },
    'th-051-discuss-the-covenant-of-grace': { q: 'What is the Covenant of Grace, per WCF VII.3 and WSC 20?', choices: ['God offers sinners life conditioned on their own unaided obedience, with no promise of the Spirit’s help to believe.', 'God offers two entirely distinct covenants of grace, one for Israel, one for the church, differing in very substance between the Old and New Testaments.', 'God freely offers sinners life and salvation by Christ, requiring faith and promising his Spirit — one covenant, differently administered.', 'God offers salvation universally and unconditionally to every person, with reprobation nowhere in view.'], answerIndex: 2 },
    'th-052a-cog-and-abrahamic-covenant': { q: 'How is the Covenant of Grace related to the Abrahamic Covenant, per the card?', choices: ['The covenant of grace was formally established at Sinai, and the Abrahamic covenant was merely a preliminary promise.', 'The covenant of grace has no meaningful relation to Abraham whatsoever; it was first formally and fully established at Pentecost with the founding of the New Testament church.', 'The covenant of grace was established with Abraham on the sole condition of his descendants’ ritual purity.', 'The covenant of grace was formally established with Abraham, marking the beginning of an institutional church responding to God’s promise by faith.'], answerIndex: 3 },
    'th-052b-cog-and-mosaic-covenant': { q: 'How is the Covenant of Grace related to the Mosaic Covenant, per the card?', choices: ['Sinai was essentially the same covenant as Abraham’s in national form; the law was made subservient to grace, tutoring Israel unto Christ.', 'Sinai replaced Abraham’s covenant entirely with a new and different covenant of works, based purely and solely on strict law-keeping for one’s own righteousness.', 'Sinai had no connection to Abraham’s covenant, introducing an unrelated ceremonial system for its own sake.', 'Sinai’s law functioned only as Israel’s civil code, with no purpose of increasing the consciousness of sin.'], answerIndex: 0 },
    'th-052c-cog-and-noahic-covenant': { q: 'How is the Covenant of Grace related to the Noahic Covenant, per the card?', choices: ['The Noahic covenant confers saving spiritual blessings only on the elect, identical in scope to the covenant of grace.', 'The Noahic covenant confers natural blessings universally as common grace, differing from yet resting on the covenant of grace.', 'The Noahic covenant has no relation whatsoever to the covenant of grace, arising from a wholly separate divine purpose.', 'The Noahic covenant confers natural blessings only on believers and their seed, excluding the rest of creation.'], answerIndex: 1 },
    'th-053-discuss-the-relationship-between-t': { q: 'How does the card describe the relationship between the Old and New Covenants?', choices: ['They are two entirely separate covenants of grace, one for Israel, one for the church, differing in substance as well as administration.', 'They are identical in every respect, with the New Covenant adding no clarity or blessing beyond the Old.', 'They are distinct in administration, yet one in substance — the same promise, redeeming God’s people in Christ, the New superior in blessing.', 'The Old Covenant remains fully in force today, with the New Covenant serving only Gentile believers.'], answerIndex: 2 },
    'th-054-explain-and-defend-with-scripture': { q: 'Per WCF VIII.2, what is the orthodox doctrine of the person of Christ?', choices: ['The eternal Son took a human nature that gradually absorbed and replaced his divine nature at the incarnation.', 'The eternal Son merely appeared to take a human nature, without truly becoming man in any real sense.', 'The eternal Son and the man Jesus are, in reality, two separate persons, loosely and only morally joined rather than united in one person.', 'The eternal Son, of one substance with the Father, took a true human nature, two distinct natures joined in one person, without confusion.'], answerIndex: 3 },
    'th-055a-was-christ-a-human-person': { q: 'Was Christ a human person, per the card’s answer?', choices: ['Not strictly — he was one divine person with two natures, human and divine, rather than a separate human person.', 'Yes — Christ was simply a human person who was later adopted by God and given divine status.', 'No — Christ had a human body only, with no genuine human nature, mind, or soul of his own at all.', 'Yes — Christ was two separate persons, a human person and a divine person, joined together.'], answerIndex: 0 },
    'th-055b-does-christ-have-a-soul': { q: 'Does Christ have a soul, per the card’s answer?', choices: ['No — Christ had only a divine nature and a human body, with no human soul of his own.', 'Yes — Christ himself said, “My soul is overwhelmed with sorrow to the point of death” (Matthew 26:38).', 'No — Christ’s divine nature functioned in the place of a human soul, so a distinct soul was unnecessary.', 'Yes, but only in a merely figurative sense, since “soul” in Matthew 26:38 simply means “life.”'], answerIndex: 1 },
    'th-055c-what-is-kenosis': { q: 'What is kenosis, per WLC 46?', choices: ['“Self-emptying” — the term for how Christ, per a mistaken reading, emptied himself of his divine nature entirely at the incarnation.', '“Self-emptying” — the term for how the Father emptied himself of glory in sending the Son to be born.', '“Self-emptying” — the term for how Christ, per WLC 46, emptied himself of his glory in taking the form of a servant.', '“Self-emptying” — the term for how the Spirit emptied himself of power at Pentecost to indwell believers.'], answerIndex: 2 },
    'th-055d-did-christ-lay-aside-any-of-his-di': { q: 'Did Christ lay aside any of his divine attributes at the incarnation, per the card?', choices: ['Yes — Christ fully laid aside all of his divine attributes, becoming entirely and only human at the incarnation.', 'No — Christ’s human nature was itself, in this view, somehow eternal and uncreated, sharing fully in every one of the divine attributes from birth.', 'Yes — Christ laid aside his moral attributes of holiness and goodness while retaining only his power and knowledge.', 'No — “in Christ all the fullness of the Deity lives in bodily form” (Col 2:9), though his body’s locality raises debate over the communicatio idiomatum.'], answerIndex: 3 },
    'th-055e-explain-and-defend-against-the-ear': { q: 'Which pairing of an early Christological heresy with its error is correct, per the card?', choices: ['Arius taught the Son was a created being, heteroousios with the Father, a view condemned at Nicea in 325.', 'Nestorius taught the Son was a created being, heteroousios with the Father, a view condemned at Nicea in 325.', 'Apollinarius taught that Christ only seemed to become a man, a view answered by John 20:24ff.', 'Eutyches taught that Christ’s two natures remained fully distinct, denying any real union between them.'], answerIndex: 0 },
    'th-055f-are-any-of-the-early-heresies-rega': { q: 'Which group does the card identify as still holding an early Christological heresy today?', choices: ['The Eastern Orthodox church, which holds a monophysite Christology in the tradition of Eutyches.', 'The Coptic church, which holds a monophysite Christology in the tradition of Eutyches.', 'The Roman Catholic church, which holds an Arian Christology denying the Son’s full deity.', 'The Anglican church, which holds a Nestorian Christology dividing Christ into two persons.'], answerIndex: 1 },
    'th-055g-explain-and-defend-the-doctrine-of': { q: 'What is the doctrine of the “communication of properties”?', choices: ['The divine nature is gradually transformed into the human nature, so that Christ’s deity becomes fully human over time.', 'The human nature is absorbed into the divine nature, so that Christ’s humanity ceases to have any real properties of its own.', 'The properties of both natures become the properties of the one person, so he can be called almighty yet also a man of sorrows.', 'The two natures exchange properties freely and completely, so the human nature becomes omniscient and the divine nature becomes mortal.'], answerIndex: 2 },
    'th-055h-what-is-the-extra-calvinisticum': { q: 'What is the “extra Calvinisticum,” per the card?', choices: ['Calvin’s view that the Son’s deity was entirely confined within the incarnate flesh, leaving heaven wholly unruled.', 'Luther’s view that the Son’s human nature became omnipresent, sharing fully in the divine attribute of ubiquity.', 'Calvin’s view that the Son set aside his divine nature at the incarnation and resumed it only after the resurrection.', 'Calvin’s view that the Son’s deity was not confined to the incarnate flesh — he ruled the world even while the God-man walked on earth.'], answerIndex: 3 },
    'th-055i-define-the-names-of-christ-jesus-s': { q: 'Which pairing of a name of Christ with its meaning is correct, per the card?', choices: ['“Son of Man” alludes to Christ’s divinity, drawing on Daniel 7:14 as Jesus’ favorite self-designation.', '“Lamb of God” alludes to Christ’s kingly rule, drawing on Daniel 7:14 as his favorite self-designation.', '“Christ” simply means “Sir,” a polite form of address used by his contemporaries before the resurrection.', '“Jesus” means “the anointed one,” translating the Hebrew term for Israel’s coming king.'], answerIndex: 0 },
    'th-055j-how-was-christ-born': { q: 'Per WSC 22, how was Christ born?', choices: ['By taking to himself a true body only, with a divine mind functioning in place of a human soul.', 'By taking to himself a true body and a reasonable soul, conceived by the Holy Ghost in the virgin Mary’s womb, and born without sin.', 'By taking to himself a human nature inherited through Joseph’s natural line, conceived and born, like any other child, without any virgin conception at all.', 'By taking to himself an apparent body only, without truly being conceived or born as other men are.'], answerIndex: 1 },
    'th-055k-explain-and-defend-including-scrip': { q: 'How does the card defend the Virgin Birth from Scripture?', choices: ['Isaiah 7:14 prophesied Christ’s resurrection, which Matthew 1:20-25 records as fulfilled through Joseph’s lineage.', 'Isaiah 7:14 has no connection to Christ’s birth; Matthew cites it only in reference to his crucifixion.', 'Isaiah 7:14 prophesied it, and Matthew 1:20-25 records its fulfillment by the Holy Spirit, without inheriting Adam’s sin nature.', 'Matthew 1:20-25 teaches that Joseph, not the Holy Spirit, was the biological father of Jesus.'], answerIndex: 2 },
    'th-055l-trace-the-revelation-of-the-person': { q: 'Which sequence correctly traces the revelation of Christ from the beginning of the Old Testament, per the card?', choices: ['The tower of Babel (Gen 11), the plagues of Egypt (Exod 7-12), and the golden calf (Exod 32), each foreshadowing Christ’s judgment.', 'The flood (Gen 6-9), the Ten Commandments (Exod 20), and the bronze serpent (Num 21), each foreshadowing Christ’s kingship.', 'Cain and Abel (Gen 4), the Tower of Babel (Gen 11), and the golden calf (Exod 32), each foreshadowing Christ’s priesthood.', 'The seed of the woman (Gen 3:15), Melchizedek’s priesthood (Gen 14), the scepter of Judah (Gen 49:10), and the Suffering Servant (Isa 53).'], answerIndex: 3 },
    'th-055m-what-is-the-humiliation-of-christ': { q: 'Per WSC 27, what is the humiliation of Christ?', choices: ['Being born in a low condition, made under the law, undergoing the miseries of this life and the wrath of God, and the cursed death of the cross.', 'Being born in royal splendor, exempt from the law, and reigning visibly over the nations from birth onward.', 'Being raised bodily, ascending to heaven, and sitting at the Father’s right hand in glory and power.', 'Being sanctified and anointed above measure with the Holy Spirit, set apart to rule and defend his church, and continually interceding for his people before the Father.'], answerIndex: 0 },
    'th-055n-define-and-distinguish-the-active': { q: 'How does the card distinguish the active and passive obedience of Christ?', choices: ['Active obedience is Christ’s suffering and death paying the penalty for sin, while passive obedience is his life of perfect obedience.', 'Active obedience is Christ’s life of perfect obedience earning righteousness for us, while passive obedience is his suffering and death paying sin’s penalty.', 'Active obedience refers only to miracles Christ performed, while passive obedience refers only to his teaching ministry.', 'Active and passive obedience both refer to the very same event, Christ’s death, viewed from two different angles.'], answerIndex: 1 },
    'th-055o-what-happened-in-the-resurrection': { q: 'What happened in the resurrection of Christ, per the card?', choices: ['A mere resuscitation identical to Lazarus’s, with no change to the nature or condition of Christ’s body.', 'A purely spiritual event with no bodily component at all, since Christ’s physical body, all admit, simply remained buried in the tomb.', 'Not mere revival, but human nature restored and raised to a higher level as “the firstfruits of them that slept,” declaring the penalty paid.', 'A symbolic event in the disciples’ memory, without any actual bodily event having taken place at all.'], answerIndex: 2 },
    'th-055p-what-are-the-offices-of-christ-and': { q: 'Per WSC 23-26, what are the offices of Christ, and how does he execute them?', choices: ['Prophet, in ruling the nations; Priest, in revealing God’s will; and King, in interceding for his people before the Father.', 'Priest only, since the offices of prophet and king belonged exclusively to the old covenant and ceased with Christ.', 'Prophet, in offering sacrifice; Priest, in ruling and defending; and King, in revealing God’s will for salvation.', 'Prophet, in revealing God’s will for our salvation; Priest, in offering himself and interceding for us; and King, in ruling and defending us.'], answerIndex: 3 },
    'th-055q-who-is-the-only-redeemer-of-god-s': { q: 'Per WSC 21, who is the only Redeemer of God’s elect?', choices: ['The Lord Jesus Christ, the eternal Son of God, who became man and continues to be God and man in two natures and one person forever.', 'The church collectively, acting as a corporate mediator between God and each individual believer.', 'Every believer individually, who redeems himself through faith and good works over a lifetime.', 'The holy angels, who are said by some to mediate between God and the elect, watching over them until the final day of judgment arrives.'], answerIndex: 0 },
    'th-055r-what-is-a-redeemer': { q: 'What is a redeemer, per the card?', choices: ['One who merely advises someone else, from a safe distance, on how to escape captivity by their own effort.', 'One who delivers someone else from captivity, securing their release at a cost to himself.', 'One who shares captivity alongside someone else without ever securing their release.', 'One who postpones someone else’s captivity without ever actually ending it.'], answerIndex: 1 },
    'th-055s-what-is-the-atonement': { q: 'What is the atonement, per the card?', choices: ['The work Christ did only in his death, since his life of obedience contributes nothing to our salvation.', 'The work each believer does in his own life, through personal effort and discipline, to earn favor with God after his own conversion.', 'The work Christ did in his life and death to earn our salvation, including the benefits flowing from his life, not only his death.', 'The work the church does in administering the sacraments to apply Christ’s life to believers.'], answerIndex: 2 },
    'th-055t-was-the-atonement-necessary-explai': { q: 'Was the atonement necessary, per the card’s answer?', choices: ['It was absolutely necessary in every sense, without exception, since God had no freedom at all in deciding whether to save anyone.', 'It was entirely unnecessary, since God could have simply overlooked sin without requiring any atonement at all.', 'It was necessary only for Gentile believers, while Jewish believers were saved through the law without atonement.', 'It was not absolutely necessary for God to save anyone, but once he chose to, there was no other way than through his Son’s death.'], answerIndex: 3 },
    'th-055u-why-isn-t-a-good-life-enough-to-ga': { q: 'Why isn’t a good life enough to gain salvation, per the card?', choices: ['Because all have sinned and fall short of the glory of God, and are by nature objects of wrath.', 'Because God simply prefers faith to good works as a matter of arbitrary personal taste.', 'Because good works are impossible for anyone to perform at all, whether believer or unbeliever.', 'Because a good life would save a person, except that no one has ever managed to live one.'], answerIndex: 0 },
    'th-055v-define-expiation-propitiation-reco': { q: 'How does the card distinguish “expiation” from “propitiation”?', choices: ['Expiation denotes the pacifying of God’s wrath, while propitiation denotes only the restoring of a broken relationship.', 'Expiation denotes the covering or putting away of sin itself, while propitiation includes that and also the pacifying of God’s wrath.', 'Expiation and propitiation are simply two unrelated words for the payment of a ransom price to captors.', 'Expiation denotes imputing Adam’s sin to us, while propitiation denotes imputing Christ’s righteousness to us.'], answerIndex: 1 },
    'th-055w-what-is-the-nature-of-the-atonemen': { q: 'What is the nature of the atonement, and what is “penal substitutionary atonement,” per the card?', choices: ['The atonement is merely subjective, intended only to influence the sinner toward repentance rather than to satisfy God.', 'The atonement is collective only, applying automatically to all humanity with no place for personal substitution.', 'The atonement is objective and vicarious, including Christ’s active and passive obedience — penal substitution unites sacrifice, propitiation, and reconciliation.', 'The atonement is merely exemplary — a moral pattern meant to inspire love, sacrifice, and courage — rather than an objective satisfaction of divine justice, wrath, and sin.'], answerIndex: 2 },
    'th-055x-what-of-christ-s-work-remains-to-b': { q: 'What of Christ’s work remains to be done, per the card?', choices: ['To be born, live a sinless life, and die on the cross, all of which still remain to be accomplished.', 'To ascend to heaven and be seated at the Father’s right hand, an event still awaited by the church.', 'To institute for the very first time the sacraments of baptism and the Lord’s Supper, ordinances which Christ has, in this view, not yet actually established.', 'To come again in great power and glory, destroy all dominion and power, defeat death, and judge the world in righteousness.'], answerIndex: 3 },
    'th-055y-were-old-testament-believers-saved': { q: 'Were Old Testament believers saved by Christ, per WCF VIII.6?', choices: ['Yes — the virtue, efficacy, and benefits of redemption were communicated to the elect in all ages through the promises and types in which Christ was revealed.', 'No — Old Testament believers were saved by their own careful and diligent obedience to the ceremonial and moral law, rather than by any faith in a coming Christ.', 'Yes, but only after Christ’s actual incarnation, so no one prior to Bethlehem could truly be saved.', 'No — salvation by faith in a coming Redeemer is strictly a New Testament category unknown before Christ.'], answerIndex: 0 },
    'th-055z-will-any-for-whom-christ-died-be-l': { q: 'Will any for whom Christ died be lost, per WCF VIII.8?', choices: ['Yes — Christ’s redemption merely makes salvation possible for all, without guaranteeing it, leaving the final outcome of each person entirely uncertain.', 'No — to all for whom Christ purchased redemption, he certainly and effectually applies it, so none of his sheep can ever be snatched away.', 'Yes — some for whom Christ died will ultimately be lost through no fault or choice of their own.', 'No, but only because believers themselves keep hold of Christ through their own unaided perseverance.'], answerIndex: 1 },
    // ── E. Salvation Accomplished ────────────────────────────────────
    'th-056-what-is-the-ordo-salutis-support-y': { q: 'What is the correct order in the ordo salutis, per the card?', choices: ['Glorification, justification, regeneration, election, effectual calling, adoption, sanctification, faith, repentance, and perseverance.', 'Sanctification, election, glorification, regeneration, justification, adoption, effectual calling, faith, repentance, and perseverance.', 'Election, gospel call, effectual calling, regeneration, repentance and faith, justification, adoption, sanctification, and glorification.', 'Regeneration, election, adoption, justification, glorification, effectual calling, sanctification, faith, repentance, and perseverance.'], answerIndex: 2 },
    'th-057-how-would-you-explain-the-plan-of': { q: 'Which sequence correctly summarizes the simple plan of salvation, per the card?', choices: ['God is holy, all have sinned, but sincere effort at good works alone is sufficient to earn eternal life.', 'God is distant and largely uninvolved in human affairs, humanity is basically good at heart, and salvation comes gradually through self-improvement alone.', 'God is holy, only some have sinned, and Christ died only for those who first proved themselves worthy.', 'God is holy, all have sinned, sin earns death but God gives life, Christ died for sinners, received by grace through faith, not works.'], answerIndex: 3 },
    'th-058-define-and-defend-include-scriptur': { q: 'Per WSC 31, what is “effectual calling”?', choices: ['The work of God’s Spirit, convincing us of our sin, enlightening our minds in Christ, and renewing our wills to embrace him.', 'The work of the sinner’s own will, convincing himself of his sin, and choosing to embrace Christ entirely unaided.', 'The general invitation of the gospel preached to all, without any inward work of the Spirit accompanying it.', 'The work of the church’s sacraments alone, apart from any inward work of conviction or renewal by the Spirit.'], answerIndex: 0 },
    'th-059-on-what-is-god-s-decision-to-call': { q: 'On what is God’s decision to call a certain person based, per WCF X.2?', choices: ['God’s foreseeing, before the world began, which persons would freely choose to respond, conditioning his call entirely on their anticipated faith.', 'God’s free and special grace alone, not from anything foreseen in man, who is passive until quickened by the Spirit.', 'The sinner’s own inherent goodness, which God recognizes and rewards with his effectual call.', 'The church’s formal decision to extend an outward call to those it judges most likely to respond.'], answerIndex: 1 },
    'th-060-how-can-infants-be-called': { q: 'How can infants be “called,” per WCF X.3?', choices: ['No infant can be saved, since the outward preaching of the Word is strictly necessary for the Spirit to work at all.', 'All infants without exception are automatically saved, since infancy itself removes any need for the Spirit’s work.', 'Elect infants dying in infancy are regenerated and saved by Christ through the Spirit, who works when and how he pleases.', 'Only infants baptized in infancy can be saved, since baptism itself effects their regeneration.'], answerIndex: 2 },
    'th-061-can-anyone-not-called-by-the-spiri': { q: 'Can anyone not called by the Spirit be saved, per WCF X.1 and X.4?', choices: ['Yes — anyone diligently following the light of nature and the laws of their own religion may also be saved.', 'Yes — common operations of the Spirit alone are sufficient to save those never effectually called.', 'No, but this is merely a matter of church discipline rather than an actual condition for salvation itself.', 'No — God predestinated only those he effectually calls, and it is pernicious to assert others can be saved by nature’s light.'], answerIndex: 3 },
    'th-062-is-jesus-really-the-only-way-of-sa': { q: 'Is Jesus really the only way of salvation, per the card?', choices: ['Yes — “no one comes to the Father except through me” (John 14:6), and salvation is found in no one else, however sincere another’s religion.', 'No — sincere adherents of any religion who diligently and faithfully follow its own laws will, in the end, also ultimately be saved.', 'Yes, but only for those born into a Christian culture; others are judged by a wholly separate standard.', 'No — general revelation alone is sufficient for salvation, apart from any explicit faith in Christ.'], answerIndex: 0 },
    'th-063-define-and-defend-include-scriptur': { q: 'Per WSC 33, what is “justification”?', choices: ['A slow process of gradual moral improvement, whereby God incrementally infuses righteousness into the believer over the course of an entire lifetime.', 'An act of God’s free grace wherein he pardons all our sins and accepts us as righteous, only for Christ’s righteousness imputed and received by faith.', 'An act of the sinner’s own will, whereby he declares himself righteous before God on the basis of his best efforts.', 'An act of the church, whereby the sacraments themselves impart the righteousness necessary for acceptance with God.'], answerIndex: 1 },
    'th-064-what-is-the-basis-of-justification': { q: 'What is the basis of justification, per WCF XI.1?', choices: ['The believer’s own infused righteousness, gradually accomplished by the Spirit’s work within the heart.', 'The believer’s sincere effort at obedience, offered in good faith, which God graciously accepts as fully sufficient for acceptance with him.', 'God’s free grace, on the basis of Christ’s imputed obedience alone — not infused righteousness, not anything wrought in us.', 'The church’s sacramental system, through which grace is dispensed to those who faithfully participate.'], answerIndex: 2 },
    'th-065-explain-this-statement-faith-alone': { q: 'What does “faith alone saves, but saving faith is never alone” mean, per WCF XI.2?', choices: ['Faith and works together are the joint instruments of justification, each contributing equally to our acceptance with God.', 'Works alone justify, since James 2 teaches that faith without deeds accomplishes nothing before God.', 'Faith is one of several equally valid instruments of justification, alongside works, sacraments, and church membership.', 'Faith alone is the sole instrument of justification, yet true saving faith is never alone but works by love.'], answerIndex: 3 },
    'th-066-when-is-a-christian-justified': { q: 'When is a Christian justified, per the card?', choices: ['At the moment of belief — God decreed to justify the elect from eternity, but applies it through the Spirit in due time.', 'At the moment of physical birth, since justification is granted automatically to every person born into the world.', 'At the final judgment alone, so that no believer can have any assurance of justification in this present life.', 'At water baptism alone, since the sacrament itself is what actually accomplishes a person’s justification.'], answerIndex: 0 },
    'th-067-what-happens-when-a-christian-sins': { q: 'What happens when a Christian sins after being justified, per WCF XI.5?', choices: ['They immediately fall out of their justified standing, entirely and completely, and must be justified all over again by a fresh act of renewed faith.', 'Nothing changes their justified standing, since it rests on Christ’s righteousness, though sin may bring God’s fatherly displeasure.', 'Their justification is only partially affected, requiring a fresh act of imputed righteousness for each sin.', 'Their justification was never genuine in the first place, since a truly justified person could not sin again.'], answerIndex: 1 },
    'th-068-how-were-believers-justified-under': { q: 'How were believers justified under the old covenant, per WCF XI.6?', choices: ['By a different and lesser justification than New Testament believers, since Christ had not yet actually died for their sins.', 'By strict obedience to the ceremonial law, apart from any exercise of faith on their part.', 'The very same way as New Testament believers — one and the same justification, with Abraham as the paradigm of faith.', 'They were not justified at all under the old covenant, only forgiven temporarily until Christ’s death.'], answerIndex: 2 },
    'th-069-define-and-defend-include-scriptur': { q: 'Per WSC 35, what is “sanctification”?', choices: ['The work of the believer’s own unaided willpower, whereby he gradually improves his moral character over time.', 'A single instantaneous event completed entirely at conversion, requiring no further growth afterward.', 'The work of the church’s sacraments alone, which mechanically produce holiness apart from the Spirit’s renewing work.', 'The work of God’s free grace whereby we are renewed after the image of God, dying more and more to sin and living unto righteousness.'], answerIndex: 3 },
    'th-070-can-anyone-become-perfect-complete': { q: 'Can anyone become perfect (completely sanctified) in this life, per WCF XIII.2 and WSC 82?', choices: ['No — sanctification is imperfect in this life, with remnants of corruption remaining, so no mere man can perfectly keep God’s commandments.', 'Yes — mature believers can and often do reach entire, sinless perfection, well before their physical death occurs.', 'Yes — sanctification is instantly completed at conversion, leaving no remaining corruption whatsoever.', 'No, but only because God has chosen arbitrarily to withhold perfection from believers who could otherwise attain it.'], answerIndex: 0 },
    // ── F. Salvation Applied ─────────────────────────────────────────
    'th-071-what-is-saving-faith-defend-your-a': { q: 'Per WSC 86, what is saving faith?', choices: ['A saving grace whereby we receive and rest upon Christ alone for salvation, as he is offered to us in the gospel.', 'A general moral conviction, sincerely held, that a supreme being exists and rewards good conduct in this present life.', 'A meritorious human work that God accepts as partial payment toward the debt of sin.', 'An emotional feeling of peace that arises spontaneously apart from any object believed in.'], answerIndex: 0 },
    'th-072-where-does-saving-faith-come-from': { q: 'Where does saving faith come from, per WCF XIV.1?', choices: ['From the sinner’s own unaided decision, made independently, before the Word, sacraments, or any work of the Spirit.', 'From the work of the Spirit of Christ in the heart, ordinarily wrought through the Word, sacraments, and prayer.', 'From inherited family tradition alone, passed down without any working of the Spirit at all.', 'From the church’s formal decree admitting a person to membership in good standing.'], answerIndex: 1 },
    'th-073-what-does-saving-faith-believe-def': { q: 'What are the principal acts of saving faith, per WCF XIV.2?', choices: ['Debating, doubting, and withholding assent until every promise of Scripture is independently verified.', 'Admiring, imitating, and outwardly conforming to Christ’s moral example without any inward trust in him.', 'Accepting, receiving, and resting upon Christ alone for justification, sanctification, and eternal life.', 'Merely assenting intellectually that Christ existed, without any personal reliance on him for salvation.'], answerIndex: 2 },
    'th-074-is-all-faith-alike-defend-your-ans': { q: 'Is all faith alike, per WCF XIV.3?', choices: ['Yes — every believer’s faith is identical in strength, unwavering, unassailed, and never varies at all from conversion onward.', 'No — faith differs in degrees, weak or strong, often assailed and weakened, yet growing toward full assurance through Christ.', 'No — some believers possess saving faith while others possess a wholly different, non-saving kind of true faith.', 'Yes — faith’s strength depends entirely on a believer’s inherited temperament rather than on Christ’s work in them.'], answerIndex: 1 },
    'th-075-define-repentance-defend-your-answ': { q: 'Per WSC 87, what is repentance unto life?', choices: ['A saving grace whereby a sinner, sensing his sin and God’s mercy, turns from it to God with grief and hatred of sin, purposing new obedience.', 'A one-time emotional outburst of remorse and regret that need not ever issue in any lasting change of heart, life, or ongoing conduct.', 'A merely legal requirement imposed by the church, unrelated to any inward sense of sin or mercy.', 'A human achievement that, once performed, itself earns the pardon of sin apart from Christ’s merit.'], answerIndex: 0 },
    'th-076-in-what-sense-is-repentance-necess': { q: 'In what sense is repentance “necessary,” per WCF XV.3?', choices: ['It is itself the meritorious cause and satisfaction for sin, apart from which pardon could never be granted.', 'It is not rested in as any satisfaction for sin, yet is of such necessity that none may expect pardon without it.', 'It is an optional devotional practice that some mature believers may choose to omit without consequence.', 'It is necessary only for especially grievous sins, while lesser sins require no repentance at all.'], answerIndex: 1 },
    'th-077-how-ought-we-to-confess-our-sins-d': { q: 'How ought believers confess their sins, per WCF XV.5-6?', choices: ['By a general repentance alone, since it is unnecessary to endeavor to repent of particular sins particularly.', 'Only through a priest’s absolution, since private confession directly to God accomplishes nothing.', 'By enduring a fixed and lengthy period of formal penance, prescribed by the church, before any assurance of pardon may rightly be received at all.', 'Every man ought to endeavor to repent of his particular sins particularly, and one who scandalizes another should also confess to them.'], answerIndex: 3 },
    'th-078-what-are-good-works-defend-your-an': { q: 'Per WCF XVI.1, what are good works?', choices: ['Only such as God has commanded in his Word, not works devised by men out of blind zeal or good intention.', 'Any sincerely intended act, whether or not it is commanded anywhere in God’s Word.', 'Whatever a person’s own conscience judges praiseworthy, regardless of Scripture’s commands.', 'Acts of religious devotion invented by church tradition to supplement Scripture’s commands.'], answerIndex: 0 },
    'th-079-what-is-the-relation-of-good-works': { q: 'What is the relation of good works to faith, per WCF XVI.2?', choices: ['Good works are the meritorious ground and foundation on which faith itself is entirely granted to the believer.', 'Good works are unrelated to faith, since one may possess either without any bearing on the other.', 'Good works replace faith as the believer matures, becoming the primary ground of acceptance with God.', 'Good works are the fruits and evidences of a true and lively faith, by which believers manifest thankfulness and glorify God.'], answerIndex: 3 },
    'th-080-are-good-works-necessary-for-salva': { q: 'Per WCF XVI.3, from where does believers’ ability to do good works come?', choices: ['Not at all of themselves, but wholly from the Spirit of Christ, requiring his actual influence to will and to do.', 'Entirely from their own natural moral strength, unaided and unassisted, by any working of the Spirit at all.', 'From the church’s sacraments alone, which mechanically produce the ability apart from the Spirit.', 'From a righteousness infused gradually at baptism that operates independently of ongoing grace.'], answerIndex: 0 },
    'th-081-can-our-good-works-save-us-defend': { q: 'Can believers’ good works merit pardon of sin or eternal life, per WCF XVI.5?', choices: ['Yes, provided the works are performed with sincere, wholehearted, and lifelong effort throughout one’s entire life.', 'No — by reason of the disproportion between our works and the glory to come, we cannot merit pardon, having only done our duty.', 'Yes, but only for especially heroic acts of self-sacrifice beyond the ordinary call of duty.', 'No, because God has decreed that good works play no role whatsoever in the Christian life.'], answerIndex: 1 },
    'th-082-can-unbelievers-do-good-works-defe': { q: 'Can unbelievers do good works, per WCF XVI.7?', choices: ['Yes, fully — works done by the unregenerate please God just as much as those done by believers.', 'No, in every sense — unbelievers are incapable of doing anything of good use to themselves or others.', 'In the matter of them, yes, and of good use; but properly no, since they proceed from no heart purified by faith and cannot please God.', 'Yes, and their neglect of such works is therefore, in every case, no more displeasing to God than their diligent performance of them.'], answerIndex: 2 },
    'th-083-define-and-defend-include-scriptur': { q: 'What is the doctrine of perseverance of the saints?', choices: ['The continuous operation of the Spirit in the believer, by which the work of grace begun in the heart is continued and brought to completion.', 'The believer’s own unaided determination to keep on persisting in faith, entirely despite the Holy Spirit’s complete absence from the process.', 'The church’s ongoing discipline, which alone secures a member’s continuance in the faith.', 'A merely hoped-for outcome with no ground in God’s election, Christ’s intercession, or the Spirit’s work.'], answerIndex: 0 },
    'th-084-can-a-saved-person-later-be-eterna': { q: 'Can a saved person later be eternally lost, per WCF XVII.1?', choices: ['Yes — even the truly regenerate may totally and finally fall away from grace and be lost forever.', 'No — those effectually called and sanctified by the Spirit can neither totally nor finally fall away, but shall certainly persevere and be saved.', 'Yes, but only if they commit a single unusually severe sin after their conversion.', 'No, but only because the church’s ongoing discipline prevents any believer from ever falling into serious or scandalous sin at all.'], answerIndex: 1 },
    'th-085-on-what-does-a-believer-s-persever': { q: 'On what does a believer’s perseverance depend, per WCF XVII.2?', choices: ['On the believer’s own unaided free will and steady personal effort, sustained by willpower rather than any promise of God.', 'On the immutability of God’s election, the efficacy of Christ’s intercession, and the Spirit’s abiding presence — not on the believer’s free will.', 'On the church’s sacraments administered faithfully, apart from any decree of election or inward work of the Spirit.', 'On God’s foreseeing, before the world’s foundation, which believers would freely choose to keep persevering to the end.'], answerIndex: 1 },
    'th-086-can-a-person-be-sure-he-is-saved-d': { q: 'Can a person be sure he is saved, per WCF XVIII.1?', choices: ['No — assurance of one’s own salvation in this present life is altogether impossible for anyone, however sincerely and earnestly they believe.', 'Yes, but only hypocrites claim it, since true believers rightly remain permanently uncertain.', 'Yes — those who truly believe in the Lord Jesus and love him in sincerity may in this life be certainly assured they are in a state of grace.', 'Yes, but such assurance is granted only after death, never during earthly life.'], answerIndex: 2 },
    'th-087-should-a-person-be-sure-he-is-save': { q: 'Per WCF XVIII.3, is it a believer’s duty to seek assurance of salvation?', choices: ['No — seeking assurance is itself a subtle form of spiritual pride that mature, humble believers ought to avoid.', 'Yes — it is the duty of every one to give diligence to make his calling and election sure, enlarging heart and peace.', 'No — assurance belongs to the very essence of faith, so every believer already possesses it fully without effort.', 'Yes, but this duty is laid only on ordained officers, never required of ordinary believers in the pew.'], answerIndex: 1 },
    'th-088-how-could-a-person-know-he-is-save': { q: 'On what is the believer’s infallible assurance founded, per WCF XVIII.2?', choices: ['A bare, conjectural, and probable persuasion grounded upon nothing more than a fallible, ever-shifting hope.', 'The divine truth of the promises, the inward evidence of the graces they concern, and the Spirit’s testimony with our own spirit.', 'Extraordinary new revelations given privately and directly only to especially mature, longstanding believers.', 'The outward approval and formal certification granted by the visible church’s courts and officers alone.'], answerIndex: 1 },
    'th-089-what-should-a-person-do-who-lacks': { q: 'What should a person who lacks assurance of salvation do, per WCF XVIII.3?', choices: ['Conclude that he is certainly not among the elect and abandon the pursuit of holiness.', 'Wait passively, since diligence in the means of grace can neither hasten nor help assurance.', 'Give all diligence to make his calling and election sure, using the ordinary means the Spirit has appointed.', 'Seek an extraordinary revelation from God, since ordinary means cannot produce assurance.'], answerIndex: 2 },
    // ── G. The Christian Life ────────────────────────────────────────
    'th-090-what-is-the-moral-law': { q: 'Per WLC 93, what is the moral law?', choices: ['The declaration of God’s will directing and binding all men to perfect and perpetual conformity, promising life and threatening death.', 'A temporary code, given only to the nation of Israel, that expired entirely once the ceremonial system was fulfilled and ended.', 'A set of civil statutes binding only nations that formally adopt them by legislation.', 'A collection of wise proverbs offered as helpful, though not obligatory, moral advice.'], answerIndex: 0 },
    'th-091-what-laws-besides-the-moral-law-di': { q: 'Per WCF XIX.3-4, what other laws did God give Israel besides the moral law?', choices: ['Ceremonial laws prefiguring Christ and judicial laws for the body politic, both now abrogated in different senses under the new covenant.', 'Only civil traffic and property statutes, since Israel, unlike other nations, had no ceremonial worship system of its own at all.', 'A second moral law distinct from the Ten Commandments, given exclusively to the priestly tribe.', 'No other laws at all — the moral law given at Sinai was the sole body of law Israel received.'], answerIndex: 0 },
    'th-092-are-believers-under-obligation-to': { q: 'Are believers under obligation to the moral law today, per WCF XIX.5-6?', choices: ['No — Christ’s gospel dissolves the moral law’s obligation entirely for all who believe.', 'Yes — the moral law forever binds all, justified persons as well as others, and Christ strengthens rather than dissolves this obligation.', 'Yes, but only as a covenant of works by which believers are still justified or condemned.', 'No — the moral law binds only unbelievers, since believers, once justified, are guided solely by the Spirit’s inward promptings.'], answerIndex: 1 },
    'th-093-what-is-theonomy-evaluate-it-bibli': { q: 'What is theonomy (Christian Reconstruction), and how does the card evaluate it?', choices: ['The view that OT judicial law and its penal sanctions still bind all nations; critiqued for overstressing covenant continuity between Israel and the church.', 'The view that no OT law of any kind bears at all on the Christian life today; the card fully and unreservedly endorses this reading.', 'The view that civil magistrates should never punish any crime at all, since every penal sanction ended with the old covenant.', 'The view that only the ceremonial law still binds the nations today, while the judicial law was wholly fulfilled in Christ.'], answerIndex: 0 },
    'th-094-where-is-the-law-of-god-summed-up': { q: 'Per WSC 41, where is the moral law summarily comprehended?', choices: ['In the parables Jesus told, memorably, throughout the four Gospels.', 'In the Ten Commandments, given by God at Mount Sinai.', 'In the ceremonial code given through Moses at Sinai.', 'In the wisdom maxims scattered through the Proverbs.'], answerIndex: 1 },
    'th-095-can-believers-keep-god-s-law-expla': { q: 'Can believers keep God’s law, per WSC 82 and WCF XIX.7?', choices: ['Yes, perfectly, the moment the Spirit begins indwelling a believer at the point of conversion.', 'No mere man can perfectly keep the commandments, though the Spirit enables the will to obey freely and cheerfully.', 'No — the law and the gospel remain locked in permanent, wholly unresolvable conflict for the believer.', 'Yes, but only by strict, careful adherence to the ceremonial law alongside the moral law of God.'], answerIndex: 1 },
    'th-096-what-is-at-stake-in-the-lordship-c': { q: 'What is at stake in the “Lordship Controversy,” per the card?', choices: ['Whether Christ’s atonement was sufficient for the elect alone, or instead for the whole world without exception.', 'Mediating between undervaluing good works as faith’s fruit and overemphasizing them so as to endanger justification.', 'Whether water baptism or a mere verbal profession is the proper ground of a person’s assurance.', 'Whether Christ’s lordship extends to the civil realm, or is confined strictly to the church alone.'], answerIndex: 1 },
    'th-097-what-are-the-means-of-grace': { q: 'Per WSC 88, what are the outward and ordinary means of grace?', choices: ['His ordinances, especially the Word, sacraments, and prayer, made effectual to the elect for salvation.', 'Only the sacraments, not the Word, prayer, or fellowship, since those are inward rather than outward and ordinary means.', 'The church’s civil influence and philanthropic works among the surrounding community.', 'Extraordinary revelations and private visions given directly to individual believers.'], answerIndex: 0 },
    'th-098-what-is-christian-liberty-explain': { q: 'Per WCF XX.1, what does Christian liberty include?', choices: ['Freedom from any obligation to obey God’s moral law, since grace removes every requirement of obedience.', 'Freedom from the guilt of sin, God’s condemning wrath, and the curse of the law, with free access to God and obedience from childlike love rather than slavish fear.', 'Freedom to worship God however each individual, congregation, or culture finds most personally meaningful, entirely apart from Scripture’s regulation.', 'Freedom solely from civil law, leaving the moral and ceremonial law fully binding as before.'], answerIndex: 1 },
    'th-099-who-or-what-is-the-lord-of-the-con': { q: 'Per WCF XX.2, who alone is Lord of the conscience?', choices: ['The visible church’s ordained officers, acting collectively through its courts.', 'God alone, who has left the conscience free from doctrines and commandments of men contrary to or beside his Word.', 'Each individual’s own private feelings, unconstrained by any external authority whatsoever.', 'The civil magistrate, who is said by some to bear the power of the sword over matters of both faith and conduct.'], answerIndex: 1 },
    'th-100-how-does-christian-liberty-bear-on': { q: 'Per WCF XX.4, how does Christian liberty relate to lawful civil and ecclesiastical power?', choices: ['Christian liberty exempts every believer from any lawful civil or ecclesiastical power whatsoever.', 'Civil and ecclesiastical powers and Christian liberty are meant mutually to uphold, not destroy, one another.', 'Christian liberty and lawful power are inherently, permanently, and irreconcilably at war, with no possible reconciliation.', 'Christian liberty applies only to ecclesiastical power, leaving civil power entirely unaddressed by it.'], answerIndex: 1 },
    'th-101-what-is-the-regulative-principle-d': { q: 'What is the regulative principle of worship, per WCF XXI.1?', choices: ['Whatever Scripture does not expressly forbid in worship may be freely practiced by the church.', 'God is to be worshiped according to his own revealed will, not according to the imaginations or devices of men.', 'Worship practices are determined chiefly by what a given culture finds most meaningful or effective.', 'The church’s tradition, apart from Scripture, is sufficient to regulate acceptable worship.'], answerIndex: 1 },
    'th-102-who-is-to-be-worshipped-defend-you': { q: 'Per WCF XXI.2, who is to be worshiped, and how?', choices: ['God, the Father, Son, and Holy Ghost, and he alone — not angels, saints, or any other creature, and since the fall, only through the mediation of Christ.', 'God the Father alone, since worship offered to the Son or Spirit would compromise the Father’s unique deity.', 'God and the saints together, since the saints’ intercession is a proper channel of worship since the fall.', 'Any being, spirit, or force sincerely believed to be divine, since sincerity rather than the object’s true identity determines worship.'], answerIndex: 0 },
    'th-103-what-are-the-ordinary-parts-or-ele': { q: 'Per WCF XXI.3-5, what are ordinary parts of religious worship?', choices: ['Only the sacraments, preaching, and private prayer, since public singing is a later addition rather than corporate worship.', 'Prayer, reading and preaching the Word, singing psalms, and the sacraments, along with oaths, vows, and fasts on their proper occasions.', 'Only silent contemplation, since vocal prayer and singing are later additions unwarranted by Scripture.', 'Whatever ceremonies the officiating minister judges most edifying on a given occasion.'], answerIndex: 1 },
    'th-104-are-christians-under-obligation-to': { q: 'Per the card, are Christians under obligation to keep a Sabbath?', choices: ['No — the Sabbath was strictly a ceremonial ordinance for Israel that expired with the old covenant.', 'Yes — the Ten Commandments represent the moral law, so the Sabbath principle of worship and rest remains binding.', 'No — the Sabbath is left entirely to each believer’s private discretion with no scriptural warrant either way.', 'Yes, but only as an optional custom observed solely by those in vocational ministry.'], answerIndex: 1 },
    'th-105-should-a-christian-ever-take-an-oa': { q: 'Per WCF XXII.1, what is a lawful oath?', choices: ['A part of religious worship in which, on just occasion, the swearer solemnly calls God to witness and judge according to truth or falsehood.', 'A purely secular legal formality with no religious character or reference to God at all.', 'An act that Scripture forbids altogether, without any exception, since Christ commands believers never to swear by heaven, earth, or anything else.', 'A private promise made silently, without solemnly invoking God as witness or judge.'], answerIndex: 0 },
    'th-106-what-should-be-our-attitude-toward': { q: 'What should a Christian’s attitude toward civil authorities be, per WCF XXIII.4 and Romans 13:1-7?', choices: ['To honor, obey, and be subject to them, since governing authorities are established by God.', 'To disregard them entirely, absolutely, since Christians answer only to Christ’s kingdom alone.', 'To obey them only when their commands align with personal preference or convenience.', 'To resist them actively whenever their policies are found imperfect or unjust.'], answerIndex: 0 },
    'th-107-what-is-the-relationship-between-c': { q: 'Per WCF XXIII.3, what is the relationship between church and state?', choices: ['The civil magistrate governs both church and state directly, administering the Word, sacraments, and the keys.', 'The church and state share no relationship whatsoever, and the magistrate owes the church nothing at all.', 'Civil magistrates may not administer the Word and sacraments, yet as nursing fathers must protect the church’s liberty.', 'The church governs the state directly, appointing and removing civil magistrates as it alone sees fit.'], answerIndex: 2 },
    'th-108-what-are-the-proper-duties-of-civi': { q: 'Per WCF XXIII.1 and XXIII.3, what are the proper duties of civil authorities?', choices: ['To administer the sacraments alongside ordained ministers so that church and state share worship duties equally.', 'To defend and encourage those who do good, punish evildoers by the power of the sword, and protect the church’s liberty as nursing fathers.', 'To remain entirely neutral toward the church, in every respect, offering it no protection, no encouragement, and no recognition whatsoever.', 'To determine true doctrine for the church, since the magistrate bears ultimate spiritual authority.'], answerIndex: 1 },
    'th-109-what-obligations-do-believers-have': { q: 'Per WCF XXIII.4, what obligations do believers have toward civil authorities?', choices: ['To pray for magistrates, honor their persons, pay tribute, and obey their lawful commands for conscience’ sake.', 'To obey civil authorities only if the magistrate professes the true faith, upholds true religion, and rules justly, otherwise owing them nothing.', 'To submit to civil authorities in name only, while withholding any actual obedience to their commands.', 'To recognize the Pope’s jurisdiction over civil magistrates in matters of religion.'], answerIndex: 0 },
    'th-110-by-whom-and-for-what-purpose-was-m': { q: 'Per WCF XXIV.2, for what purposes was marriage ordained?', choices: ['For political alliance between ruling families and for accumulating property across the generations.', 'For the mutual help of husband and wife, increasing mankind with a legitimate issue, and preventing uncleanness.', 'For romantic companionship alone, for personal fulfillment, with procreation regarded as a purely optional byproduct of marriage.', 'For the church’s own convenience in administering its membership rolls and sacramental records.'], answerIndex: 1 },
    'th-111-who-may-and-may-not-lawfully-be-ma': { q: 'Per WCF XXIV.1 and XXIV.3, who may lawfully be married?', choices: ['Any two consenting adults regardless of their sex, since Scripture, in this view, places no limits at all on the sex of the parties.', 'One man and one woman able to give consent with judgment, with Christians urged to marry only in the Lord rather than being unequally yoked.', 'Only those matched by their families for economic advantage, regardless of personal consent.', 'Any number of wives to one husband, provided each wife freely consents to the arrangement.'], answerIndex: 1 },
    'th-112-what-is-divorce': { q: 'What is divorce, per WCF XXIV.6 and Genesis 2:24?', choices: ['A temporary separation that automatically reverses itself once tensions between the spouses subside.', 'The official dissolution of the one-flesh union between husband and wife.', 'A purely civil legal formality with no bearing on the marriage bond itself before God.', 'A private feeling of estrangement that requires no formal act to take effect.'], answerIndex: 1 },
    'th-113-under-what-circumstances-is-divorc': { q: 'Under what circumstances is divorce permissible, per WCF XXIV.6?', choices: ['For any cause at all that a spouse judges sufficient, convenient, or desirable, so long as the civil magistrate is notified.', 'Nothing but adultery or unremedied desertion is sufficient cause, and then only by a public, orderly process.', 'Only financial hardship or plain differences of personality between the two spouses involved.', 'Divorce is never permissible under any circumstance whatsoever for a professing Christian.'], answerIndex: 1 },
    'th-114-is-divorce-an-option-for-those-abu': { q: 'Per the card, is divorce an option for a spouse suffering ongoing physical abuse?', choices: ['No — abuse is never a biblically recognized ground for divorce under any circumstance.', 'Yes — the card classes such abuse as an instance of desertion, one of the recognized grounds.', 'Yes, but only if the abusing spouse is formally excommunicated by the church first.', 'No — the abused spouse must remain in the marriage and simply seek civil protection instead.'], answerIndex: 1 },
    'th-115-may-those-who-have-been-divorced-r': { q: 'Per the card, may a person legitimately divorced under WCF XXIV.6 remarry?', choices: ['No — remarriage after any divorce constitutes ongoing adultery for the remainder of that person’s life.', 'Yes — 1 Corinthians 7:15’s “not bound” and the exception clause of Matthew 19:9 support the permissibility of remarriage.', 'Yes, but only if the remarriage occurs in a different congregation than the original marriage.', 'No — Scripture is entirely silent on the question of remarriage after divorce.'], answerIndex: 1 },
    // ── H. The Church ────────────────────────────────────────────────
    'th-116-what-is-the-universal-or-catholic': { q: 'Per WCF XXV.1, what is the catholic or universal church?', choices: ['The whole number of the elect, past, present, and future, gathered under Christ as Head — the invisible church.', 'Every professing denomination, worldwide, presently in visible fellowship and communion with the Roman see.', 'Only those believers who happen to be presently alive on earth at any single given moment.', 'The visible institution formally recognized by civil governments as their established state religion.'], answerIndex: 0 },
    'th-117-what-is-the-visible-church': { q: 'Per WCF XXV.2, what is the visible church?', choices: ['Only those individuals whose personal election is outwardly evident beyond any doubt.', 'A single nation set apart under the law, its scope unchanged under the new covenant era.', 'All who profess the true religion worldwide, with their children — the kingdom of Christ on earth.', 'A voluntary society bearing no particular connection to the ordinary means of salvation.'], answerIndex: 2 },
    'th-118-what-are-the-attributes-of-the-chu': { q: 'Per Berkhof, to what is the church’s unity, holiness, and catholicity primarily ascribed?', choices: ['Primarily to the church as an invisible organism, and only secondarily to the church as an external institution.', 'Primarily to the visible institution’s formal denominational structure, with the invisible church in view only secondarily.', 'Equally and identically to the visible and invisible church, with no priority given to either.', 'Solely to individual believers considered apart from any corporate identity at all.'], answerIndex: 0 },
    'th-119-what-are-the-marks-of-the-church-p': { q: 'Per WCF XXV.4, what makes a particular church more or less pure?', choices: ['By the size, prestige, and architectural grandeur of its membership roll and building.', 'By its degree of political influence and standing within the surrounding civil community.', 'As the gospel is taught and embraced, sacraments administered, and worship performed more or less purely.', 'By its formal recognition granted through vote of an ecumenical council of bishops.'], answerIndex: 2 },
    'th-120-who-is-the-head-of-the-church-prov': { q: 'Per WCF XXV.6, who is the head of the church?', choices: ['The Pope of Rome, as the historic successor of the apostle Peter.', 'The Lord Jesus Christ alone — the Pope cannot in any sense be head of the church.', 'Each local congregation’s own senior pastor, acting as its functional head.', 'The civil magistrate, who bears ultimate authority over the church’s affairs.'], answerIndex: 1 },
    'th-121-define-three-basic-forms-of-church': { q: 'Which pairing of a church government form with its structure is correct, per the card?', choices: ['Episcopalian: elected elders serve in graded courts of session, presbytery, and general assembly.', 'Presbyterian: government entrusted exclusively to bishops as apostolic successors, with the congregation having no share.', 'Congregational: each church is complete and independent, with wider fellowship being merely advisory.', 'Episcopalian and Congregational are simply two names for the very same form of government.'], answerIndex: 2 },
    'th-122-what-are-the-principles-of-presbyt': { q: 'Which is a principle of Presbyterian church government, per Berkhof and the card?', choices: ['Christ is the Head of the church and the source of all its authority, exercised by his royal Word through representative organs.', 'Each congregation, entirely on its own, governs itself apart from any binding connection to other congregations.', 'A single bishop holds exclusive authority over all churches within a diocese.', 'The civil magistrate determines the church’s doctrine and worship by legislative enactment.'], answerIndex: 0 },
    'th-123-may-women-serve-as-officers-in-the': { q: 'Per the card, may women serve as elders or deacons in the PCA?', choices: ['Yes, without restriction, since 1 Timothy 2 addresses only a passing first-century situation.', 'No — elder and deacon are restricted to men by the creation order, though women have vital gospel ministries.', 'No, and further, women are excluded from any teaching or service ministry whatsoever in the church.', 'Yes, but only in the office of deacon, and never in the teaching or ruling eldership.'], answerIndex: 1 },
    'th-124-what-is-subscription': { q: 'What is “subscription,” per the card?', choices: ['Receiving the Westminster standards as containing Scripture’s system of doctrine — the second ordination vow.', 'A financial pledge an ordained officer makes annually toward the denomination’s operating budget.', 'The formal act of joining a particular local congregation as an accountable communicant member.', 'A vow taken only by deacons, quite distinct from the vows required of ruling and teaching elders.'], answerIndex: 0 },
    'th-125-what-privileges-do-christians-shar': { q: 'Per WCF XXVI.1 and WLC 63, what privileges do Christians share?', choices: ['Fellowship with Christ, communion in one another’s gifts, and the church’s special care and means of salvation.', 'Immunity from all earthly suffering, hardship, and grief, guaranteed to every professing believer alive.', 'An equal share in Christ’s own divine nature and essence, as fellow partakers of the Godhead.', 'Exemption from every duty owed to fellow believers, since privileges entail no obligations.'], answerIndex: 0 },
    'th-126-what-duties-do-christians-owe-one': { q: 'Per WCF XXVI.1-2, what duties do Christians owe one another?', choices: ['To maintain holy fellowship in worship, relieve one another’s needs, and use freedom thoughtfully.', 'Only formal attendance at corporate worship, private devotion, and public prayer, with no obligation toward the needs of others at all.', 'To submit every dispute exclusively to the civil courts rather than seek reconciliation in the church.', 'To avoid any material assistance to fellow believers, for fear of fostering their dependency.'], answerIndex: 0 },
    'th-127-does-the-communion-of-the-saints-d': { q: 'Per WCF XXVI.3, does the communion of the saints deny the right of private property?', choices: ['Yes — communion with Christ and with one another requires all believers to hold every possession entirely in common.', 'No — communion with the saints does not take away or infringe the title or property each person has in their own goods.', 'Yes, but only for those in vocational ministry, who must relinquish personal property.', 'No, because the question of property was never addressed by the Westminster Assembly at all.'], answerIndex: 1 },
    'th-128-what-authority-does-the-church-pos': { q: 'Per WCF XXX.2, what authority (the “keys of the kingdom”) do church officers possess?', choices: ['Power to retain and remit sins, shut the kingdom against the impenitent, and open it to the penitent.', 'Power to forgive sins in a way that operates entirely apart from any actual repentance by the sinner.', 'Civil power to imprison, fine, or otherwise punish offenders, exercised jointly alongside the state’s own civil magistrates.', 'Power confined strictly to administering the sacraments, with no authority over discipline at all.'], answerIndex: 0 },
    'th-129-what-is-the-purpose-of-church-cens': { q: 'Per WCF XXX.3, what are the purposes of church censures?', choices: ['Reclaiming the offending brother, deterring others, purging the church, and vindicating Christ’s honor.', 'Punishing offenders, publicly and severely, in proportion to the embarrassment caused to the congregation’s reputation.', 'Raising needed revenue for the church through fines levied directly against disciplined members.', 'Permanently barring an offender from ever being restored to the church’s ongoing fellowship again.'], answerIndex: 0 },
    'th-130-what-censures-may-the-church-impos': { q: 'Per WCF XXX.4, what censures may church officers impose?', choices: ['Only excommunication, reserved for the single most severe class of offense.', 'Admonition, suspension from the Lord’s Supper for a season, and excommunication, according to the nature of the crime.', 'Civil fines and imprisonment, administered jointly with the state.', 'Public shaming alone, without formality, and without any actual exclusion from sacraments or membership.'], answerIndex: 1 },
    'th-131-identify-some-scripture-passages-t': { q: 'Which passage supplies the procedure for church discipline the card cites?', choices: ['1 Corinthians 5:3-13, on expelling, formally and publicly, the unrepentant from the congregation.', 'Matthew 18:15-17, on going to a sinning brother privately, then with witnesses, then to the church.', 'Titus 1:10-14, on rebuking false teachers sharply.', '2 Corinthians 2:5-11, on forgiving and comforting a repentant offender.'], answerIndex: 1 },
    'th-132-who-may-properly-call-church-assem': { q: 'Per WCF XXXI.1, who may properly call synods or councils?', choices: ['Any individual church member who judges a matter urgent enough to warrant a wider assembly.', 'The civil magistrate alone, acting by his own authority, since ecclesiastical assemblies require state permission to convene.', 'The overseers and other rulers of the particular churches, by virtue of their office, for the church’s edification.', 'A rotating committee of laypeople elected annually for that specific purpose.'], answerIndex: 2 },
    'th-133-what-authority-do-church-councils': { q: 'Per WCF XXXI.3, what authority do synods and councils possess, and how should Christians respond to them?', choices: ['They are infallible once convened, beyond all question, so their decrees bind the conscience absolutely without exception.', 'They may err, as many have, and so are not to be made the rule of faith or practice but used as a help in both.', 'They possess no authority whatsoever and may be disregarded freely by any believer.', 'They possess civil as well as ecclesiastical authority, empowering them to legislate for the commonwealth.'], answerIndex: 1 },
    // ── I. Last Things ───────────────────────────────────────────────
    'th-134-what-happens-to-believers-at-death': { q: 'What happens to believers’ souls at death, per WCF XXXII.1 and WSC 37?', choices: ['They sleep in an unconscious state until the resurrection, unaware of anything until that day.', 'They are made perfect in holiness and immediately pass into glory, beholding God’s face while their bodies rest in the grave.', 'They are annihilated at death, to be recreated only at the final resurrection.', 'They remain bound to their bodies in the grave until Christ’s return, experiencing absolutely nothing at all until then.'], answerIndex: 1 },
    'th-135-what-happens-to-unbelievers-at-dea': { q: 'What happens to the souls of the wicked at death, per WCF XXXII.1?', choices: ['They cease to exist entirely, with no conscious experience of any kind after death.', 'They are cast into hell, remaining in torments and utter darkness reserved to the judgment of the great day.', 'They are given a further opportunity to repent during an intermediate state.', 'They are reincarnated into another earthly body to work out their own salvation in a future life.'], answerIndex: 1 },
    'th-136-who-will-be-raised-to-life-at-the': { q: 'Per WCF XXXII.2, who will be raised at the last day, and how?', choices: ['Only the righteous, at the last day, will be raised bodily; the wicked remain forever disembodied in hell.', 'All the dead shall be raised up with the self-same bodies, though with different qualities, reunited to their souls forever.', 'Only those alive at Christ’s coming will receive resurrection bodies; the previously dead remain as souls only.', 'No bodily resurrection occurs at all — the last day concerns only the souls of the departed.'], answerIndex: 1 },
    'th-137-who-will-be-judged-at-the-last-day': { q: 'Per WCF XXXIII.1, who will be judged at the last day?', choices: ['Only unbelievers will be judged; believers are exempted entirely from appearing before Christ’s tribunal.', 'Not only the apostate angels but all persons who have ever lived shall appear before Christ’s tribunal to give an account.', 'Only those who died without ever hearing the gospel will be judged, since others are judged in this life.', 'Only the nations collectively will be judged, with no individual accounting required.'], answerIndex: 1 },
    'th-138-by-whom-will-they-be-judged-defend': { q: 'By whom will people and angels be judged, per WCF XXXIII.1 and 1 Corinthians 6:3?', choices: ['People will be judged by Jesus Christ, to whom all judgment is given by the Father; believers will judge angels.', 'Angels will judge both people and fellow angels, with Christ presiding only ceremonially.', 'Each person will judge himself according to his own conscience, with no external judge involved.', 'The Father alone will judge, with the Son and Spirit playing no role in the final judgment.'], answerIndex: 0 },
    'th-139-will-any-receive-a-second-chance-d': { q: 'Will anyone receive a second chance to believe after death, per WCF XXXIII.1 and Hebrews 9:27?', choices: ['Yes — those who die without faith may still repent and believe during an intermediate purifying state.', 'No — man is destined to die once and after that to face judgment, receiving according to what was done in the body.', 'Yes, but only for those who lived before the gospel was preached to any nation.', 'No, but only because God has arbitrarily chosen to withhold any further opportunity, not because judgment follows death.'], answerIndex: 1 },
    'th-140-what-practical-use-is-the-doctrine': { q: 'Per WCF XXXIII.3, what practical uses does the doctrine of the final judgment serve?', choices: ['It deters all from sin and offers greater consolation to the godly in adversity, while its unknown timing keeps believers watchful.', 'It serves only to frighten unbelievers, offering no comfort or motivation to believers at all.', 'It has no practical use, since the timing and certainty of judgment are unknowable and therefore irrelevant to daily life.', 'It functions solely as a doctrine for theological debate, without any bearing on Christian conduct.'], answerIndex: 0 },
    'th-141-when-will-christ-return-defend-you': { q: 'When will Christ return, per WCF XXXIII.3 and Matthew 24:36-44?', choices: ['On a precisely calculable date, year, and hour, once believers correctly interpret the relevant prophetic timelines.', 'At a day unknown to men, unexpectedly like a thief, yet imminently — his day is kept hidden so believers stay watchful.', 'Only after every nation on earth has been fully Christianized without exception.', 'At the exact moment predicted by the fig tree parable, dated from the founding of modern Israel.'], answerIndex: 1 },
    'th-142-what-will-heaven-be-like': { q: 'Per the card’s reading of Revelation 21-22, what will the eternal state be like?', choices: ['A wholly disembodied spiritual existence, forever apart from any body, since the present physical creation will be annihilated rather than renewed.', 'The dwelling of God with his people — joy, light, and eternal life — on a redeemed physical creation, with Christ’s resurrection body as the paradigm.', 'An exact replica of first-century Jerusalem, restored physically and politically under a Davidic monarchy.', 'A return to a purely spiritual Eden with no continuity at all to the present created order.'], answerIndex: 1 },
    'th-143-is-there-a-hell-defend-your-answer': { q: 'Per the card’s Scripture proofs (Matthew 13:40-42; Mark 9:47-48; 2 Thessalonians 1:9), is there a hell?', choices: ['No — these passages are purely figurative warnings with no reference to any actual future punishment.', 'Yes — Scripture describes a real fiery judgment and everlasting destruction for those who do evil.', 'Yes, but only as a temporary purifying process that eventually restores all people to God.', 'No — hell is simply a metaphor for the natural consequences of sin experienced in this present life.'], answerIndex: 1 },
    'th-144-what-is-annihilationism-evaluate-i': { q: 'What is annihilationism, and how does the card evaluate it biblically?', choices: ['The view that unbelievers cease to exist rather than suffer eternal conscious torment; the card judges it inconsistent with texts like Revelation 20:10 and the parallelism of Matthew 25:46.', 'The view that all people, both believers and unbelievers alike, will eventually be reconciled to God and saved in the end; the card fully and unreservedly endorses this reading.', 'The view that hell is a present reality on earth rather than a future state; the card affirms this as the correct interpretation.', 'The view that only fallen angels, not human beings, face any form of eternal punishment; the card agrees with this distinction.'], answerIndex: 0 },
    'th-145-what-is-your-view-of-the-millenniu': { q: 'What millennial view does the card defend, and on what basis?', choices: ['Premillennial — Revelation 20 describes a future thousand-year earthly reign of Christ beginning after his return.', 'Amillennial — the NT reinterprets OT Israel-imagery as fulfilled in the church, and Revelation 20’s reign is Christ’s present heavenly reign with departed saints since his first coming.', 'Postmillennial — the millennium is a future golden age the church gradually achieves through the near-total conversion of the whole world before Christ’s final return.', 'Dispensational premillennial — Israel and the church remain wholly distinct programs, each with a separate future in the millennium.'], answerIndex: 1 },
    'th-146-what-does-the-bible-teach-about-th': { q: 'What did the Holy Spirit do in the Old Testament, per the card?', choices: ['Nothing — the Spirit’s work is exclusively a New Testament, post-Pentecost phenomenon.', 'Shaping creation, revealing God’s messages to his spokesmen, teaching faithfulness, and eliciting faith and repentance in believers such as the psalmists.', 'Only empowering the priesthood for ceremonial duties, with no bearing on ordinary believers’ faith.', 'Only inspiring pagan prophets outside Israel, in a general way, while Israel’s own true prophets worked entirely apart from the Spirit’s influence.'], answerIndex: 1 },
    'th-147-what-is-the-holy-spirit-s-function': { q: 'How does the card describe the difference between the Spirit’s OT and NT ministry?', choices: ['There is no difference whatsoever at all — the Spirit’s ministry is identical across both testaments.', 'In the OT the Spirit pointed prophets to Christ’s coming; in the NT he indwells believers as the exalted Christ’s Spirit.', 'In the OT the Spirit indwelt only Gentiles; in the NT the Spirit indwells only Jews and no one else.', 'The Spirit’s NT ministry is strictly lesser than his OT ministry, since Pentecost diminished his work.'], answerIndex: 1 },
    'th-148-what-happened-at-pentecost-how-doe': { q: 'What happened at Pentecost, per the card, and what is its ongoing significance?', choices: ['It was a one-time historical event with no bearing on the church’s life or experience today.', 'It marked the transition to the new covenant, pouring the Spirit on all people without ethnic limit.', 'It restricted the Spirit’s presence to the apostles alone, ending with the last apostle’s death.', 'It reestablished the ceremonial law’s requirements for believers regardless of their ethnicity.'], answerIndex: 1 },
    'th-149-distinguish-between-the-gifts-and': { q: 'How does the card distinguish the gifts of the Spirit from the fruit of the Spirit?', choices: ['Gifts and fruit are simply two different names for the very same reality described in Galatians 5.', 'Gifts build up the church’s ministry (Rom 12; 1 Cor 12-14; Eph 4), while fruit is the personal transformation of a believer’s character (Gal 5:22-23).', 'Gifts concern only personal character transformation within the believer, while fruit concerns building up the church corporately and publicly.', 'Only ordained officers may receive gifts, while fruit is reserved for the laity alone.'], answerIndex: 1 },
    'th-150-does-the-spirit-give-gifts-today-e': { q: 'Does the Spirit give gifts today, per the card?', choices: ['No — spiritual gifts ceased entirely with the death of the last apostle.', 'Yes — the passages describing the gifts clearly have validity today.', 'No — gifts were given only for the duration of the apostolic council at Jerusalem.', 'Yes, but only the gift of tongues remains valid; all others have ceased.'], answerIndex: 1 },
    'th-151-are-there-gifts-mentioned-in-scrip': { q: 'Per the card, are there gifts mentioned in Scripture that are not given today?', choices: ['Yes — prophecy and teaching both ceased once the New Testament canon was fully completed.', 'No — though gifts like healings and tongues may be less prominent, not given automatically even then.', 'Yes — every single gift listed in 1 Corinthians 12 except love has now permanently ceased.', 'No, and moreover every gift is given equally and constantly to each believer without exception.'], answerIndex: 1 },
    'th-152-what-do-new-testament-passages-tea': { q: 'Per the card’s survey of NT passages, what does the Spirit do for believers?', choices: ['He reveals Christ’s reality, unites believers to Christ, assures them of adoption, transforms them morally, and enables spiritual gifts.', 'He functions only as a symbolic figure, a mere metaphor, representing God’s general presence in the world, with no personal activity of his own.', 'He works exclusively through ordained clergy, with no direct ministry to ordinary believers.', 'He primarily governs the physical creation, with no direct ministry within individual believers.'], answerIndex: 0 },
    'th-153-how-would-you-answer-charismatic-c': { q: 'Per the card, how should a Mormon claim that “as man is, God once was” be answered?', choices: ['By affirming the claim, since Scripture nowhere addresses God’s eternal nature.', 'By appealing to Psalm 90:2 and John 1:1-2, which affirm God’s eternal, uncreated existence “from everlasting to everlasting.”', 'By conceding the philosophical point while denying only its biblical basis.', 'By arguing that God’s eternality is, in fact, a later New Testament innovation absent from the entire Old Testament.'], answerIndex: 1 },
    // ── K. Other Questions: Holy Spirit & Defending the Faith ────────
    'th-k-001': { q: 'What did the Holy Spirit do in the Old Testament, per the card?', choices: ['Nothing of note — the Spirit’s activity is a strictly New Testament, post-Pentecost phenomenon.', 'Hovered over creation, empowered judges and kings, inspired prophecy, and renewed hearts among his people.', 'Only inspired pagan diviners outside Israel, never Israel’s own prophets or covenant leaders.', 'Merely symbolized wind and breath, with no personal, active work attributed to him at all.'], answerIndex: 1 },
    'th-k-002': { q: 'Per the card, what is new about the Spirit’s work since Pentecost, if his saving work is the same in every age?', choices: ['Nothing changed at Pentecost; the Spirit’s ministry, in measure, scope, and effect, is entirely identical before and after.', 'The measure and scope — he now indwells the whole church, Jew and Gentile, as the permanent down payment of the age to come.', 'The Spirit only began regenerating sinners after Pentecost, having done nothing of the kind previously.', 'The Spirit’s work became temporary rather than permanent once poured out at Pentecost.'], answerIndex: 1 },
    'th-k-003': { q: 'What kind of event was Pentecost, per the card?', choices: ['A repeatable pattern, common and ordinary, every believer should expect to personally re-experience in their own life.', 'A once-for-all, unrepeatable redemptive-historical event, like the cross, whose gift belongs to all who believe.', 'A minor local occurrence carrying no lasting redemptive-historical significance for the church.', 'An event confined to restoring Israel’s national fortunes, with no bearing on Gentile believers.'], answerIndex: 1 },
    'th-k-004': { q: 'How does the card distinguish spiritual gifts from the fruit of the Spirit?', choices: ['Gifts are diverse abilities for building up the church; fruit is the uniform character the Spirit grows in each believer.', 'Gifts and fruit are simply two different names for the same reality described throughout Galatians 5.', 'Fruit is diverse and distributed selectively, while gifts are uniform and expected equally of everyone.', 'Gifts concern only personal godliness, while fruit concerns the church’s corporate ministry and structure.'], answerIndex: 0 },
    'th-k-005': { q: 'Per the card, what do both cessationists and continuationists affirm regarding the sign gifts debate?', choices: ['That new revelation today may supplement Scripture provided it does not directly contradict it.', 'That Scripture is complete and sufficient and the apostolic foundation was unique — no purported gift may add to or rival the closed canon.', 'That the apostolic office continues today through a line of successors who still receive revelation.', 'That the question is settled definitively and finally within the PCA, with only one confessionally acceptable answer ever permitted.'], answerIndex: 1 },
    'th-k-006': { q: 'Per the card, how should the claim “as God is, man may become” (Mormon theology) be answered from Scripture?', choices: ['By appealing to Isaiah 43:10 and John 4:24, which teach one eternal God who is spirit, not an exalted man.', 'By conceding the point, since Scripture nowhere directly addresses the nature of God’s being.', 'By appealing solely to church tradition, since Scripture is silent on the nature of God.', 'By arguing the claim is essentially compatible with the biblical, historic, and confessional doctrine of theosis.'], answerIndex: 0 },
    'th-k-007': { q: 'Per the card, how should a Jehovah’s Witness denial of Christ’s full deity be answered?', choices: ['By conceding that Colossians 1:15’s “firstborn” proves Christ is a created being subordinate to the Father.', 'By appealing to John 1:1, John 8:58, John 20:28, and Colossians 1:16-17, which affirm Christ’s full, uncreated deity.', 'By avoiding John 1:1, John 8:58, and John 20:28 entirely, since their grammar is too disputed to settle the question.', 'By arguing Christ’s deity is a later church invention absent from the earliest New Testament writings.'], answerIndex: 1 },
  };
  global.PCA_CARD_QUIZ = Object.assign(global.PCA_CARD_QUIZ || {}, Q);
})(typeof window !== 'undefined' ? window : globalThis);
